from fastapi import FastAPI, HTTPException, Header, Depends
from typing import Optional
import secrets
import bcrypt

app = FastAPI()

users = {}
next_user_id = 1
tokens = {}
resource_types = {}
next_resource_ids = {}
moderators = set()
admins = set()

RESERVED_ROUTES = {"signup", "login", "promote"}


def hash_password(password: str) -> str:
    return bcrypt.hashpw(password.encode("utf-8"), bcrypt.gensalt()).decode("utf-8")


def verify_password(plain: str, hashed: str) -> bool:
    return bcrypt.checkpw(plain.encode("utf-8"), hashed.encode("utf-8"))


def get_current_user(authorization: Optional[str] = Header(None)):
    if not authorization:
        raise HTTPException(status_code=401, detail="Missing auth token")
    token = authorization.replace("Bearer ", "")
    if token not in tokens:
        raise HTTPException(status_code=401, detail="Invalid token")
    return tokens[token]


@app.post("/signup")
def signup(username: str, password: str):
    global next_user_id
    for u in users.values():
        if u["username"] == username:
            raise HTTPException(status_code=400, detail="Username taken")
    if not username or not password:
        raise HTTPException(status_code=400, detail="Username and password required")
    user_id = next_user_id
    next_user_id += 1
    hashed = hash_password(password)
    users[user_id] = {"id": user_id, "username": username, "password": hashed}
    return {"id": user_id, "username": username}


@app.post("/login")
def login(username: str, password: str):
    matched_user = None
    for u in users.values():
        if u["username"] == username:
            matched_user = u
            break

    # Always run verify_password to avoid timing-based user enumeration.
    # Use a dummy hash when no user is found so the timing is consistent.
    dummy_hash = hash_password("dummy_password_to_prevent_timing_attack")
    candidate_hash = matched_user["password"] if matched_user else dummy_hash

    if matched_user and verify_password(password, candidate_hash):
        token = secrets.token_hex(32)
        tokens[token] = matched_user["id"]
        return {"token": token}

    raise HTTPException(status_code=401, detail="Invalid credentials")


@app.post("/promote/{user_id}")
def promote_user(user_id: int, authorization: Optional[str] = Header(None)):
    current = get_current_user(authorization)
    if current not in admins:
        raise HTTPException(status_code=403, detail="Not admin")
    if user_id not in users:
        raise HTTPException(status_code=404, detail="User not found")
    moderators.add(user_id)
    return {"status": "promoted", "user_id": user_id}


@app.post("/{resource}")
def create_resource(resource: str, data: dict, authorization: Optional[str] = Header(None)):
    current = get_current_user(authorization)

    if resource in RESERVED_ROUTES:
        raise HTTPException(status_code=400, detail="Invalid resource type")

    if resource not in resource_types:
        resource_types[resource] = {}
        next_resource_ids[resource] = 1

    res_id = next_resource_ids[resource]
    next_resource_ids[resource] += 1

    # Prevent mass assignment: strip any attempt by the client to control
    # server-managed fields such as 'id' and 'owner'.
    data.pop("id", None)
    data.pop("owner", None)

    safe_data = dict(data)
    safe_data["id"] = res_id
    safe_data["owner"] = current

    resource_types[resource][res_id] = safe_data
    return {"id": res_id, **safe_data}


@app.get("/{resource}/{resource_id}")
def get_resource(resource: str, resource_id: int, authorization: Optional[str] = Header(None)):
    current = get_current_user(authorization)
    if resource not in resource_types:
        raise HTTPException(status_code=404, detail="Resource type not found")
    if resource_id not in resource_types[resource]:
        raise HTTPException(status_code=404, detail="Resource not found")
    return resource_types[resource][resource_id]
