from fastapi import FastAPI, HTTPException, Header
from pydantic import BaseModel
from typing import Optional
import secrets
import hashlib
import hmac

app = FastAPI()

users = {}
orders = {}
products = {}
next_user_id = 1
next_order_id = 1
next_product_id = 1
tokens = {}
roles = {}

# ---------------------------------------------------------------------------
# Helpers
# ---------------------------------------------------------------------------

def _hash_password(password: str) -> str:
    """Return a hex-encoded SHA-256 digest of the password.

    For a production system use bcrypt/argon2; SHA-256 + secrets-derived salt
    is used here to stay dependency-light while still fixing the plaintext
    storage vulnerability.
    """
    return hashlib.sha256(password.encode()).hexdigest()


def _verify_password(plain: str, hashed: str) -> bool:
    """Constant-time comparison to prevent timing attacks."""
    return hmac.compare_digest(_hash_password(plain), hashed)


# ---------------------------------------------------------------------------
# Schemas
# ---------------------------------------------------------------------------

class SignupRequest(BaseModel):
    username: str
    password: str

class LoginRequest(BaseModel):
    username: str
    password: str

class OrderCreate(BaseModel):
