from fastapi import FastAPI, HTTPException, Header
from typing import Optional
import uuid
import secrets
import hashlib

app = FastAPI()

users = {}
tokens = {}
vip_users = set()
next_user_id = 1
resources = {}


def hash_password(password: str) -> str:
    """Hash a password using SHA-256 with a random salt."""
    salt = secrets.token_hex(16)
    hashed = hashlib.sha256((salt + password).encode()).hexdigest()
    return f"{salt}:{hashed}"


def verify_password(password: str, stored: str) -> bool:
    """Verify a password against a stored salt:hash string."""
    try:
        salt, hashed = stored.split(":", 1)
    except ValueError:
        return False
    expected = hashlib.sha256((salt + password).encode()).hexdigest()
    return secrets.compare_digest(expected, hashed)


def get_current_user(authorization: Optional[str] = Header(None)):
    if not authorization:
        raise HTTPException(status_code=401, detail="No auth token")
    # Support both "Bearer <token>" and raw token
    token = authorization.removeprefix("Bearer ").strip()
    # Use a timing-safe lookup: find the token via compare_digest to avoid
    # leaking token existence through timing differences.
    matched_user_id = None
    for stored_token, user_id in tokens.items():
        if secrets.compare_digest(stored_token, token):
            matched_user_id = user_id
            break
    if matched_user_id is None:
        raise HTTPException(status_code=401, detail="Invalid token")
    return matched_user_id


@app.post("/signup")
def signup(username: str, password: str):
    global next_user_id
    for u in users.values():
        if u["username"] == username:
            raise HTTPException(status_code=400, detail="Username taken")
    if not username or not password:
        raise HTTPException(status_code=400, detail="Username and password are required")
    user_id = next_user_id
    next_user_id += 1
    # Store a hashed password, never plaintext
    users[user_id] = {
        "id": user_id,
        "username": username,
        "password": hash_password(password),
        "vip": False,
    }
    return {"user_id": user_id, "username": username}


@app.post("/login")
def login(username: str, password: str):
    for u in users.values():
        if u["username"] == username and verify_password(password, u["password"]):
            token = secrets.token_urlsafe(32)  # cryptographically secure token
            tokens[token] = u["id"]
            return {"token": token}
    raise HTTPException(status_code=401, detail="Invalid credentials")


@app.post("/promote/{user_id}")
def promote_user(user_id: int, authorization: Optional[str] = Header(None)):
    current_user_id = get_current_user(authorization)
    if current_user_id not in vip_users:
        raise HTTPException(status_code=403, detail="Only VIP users can promote")
    if user_id not in users:
        raise HTTPException(status_code=404, detail="User not found")
    users[user_id]["vip"] = True
    vip_users.add(user_id)
    return {"message": f"User {user_id} promoted to VIP"}


@app.get("/{resource}/{resource_id}")
def get_resource(
    resource: str,
    resource_id: int,
    authorization: Optional[str] = Header(None),
):
    current_user_id = get_current_user(authorization)
    if resource not in resources:
        raise HTTPException(status_code=404, detail="Resource type not found")
    if resource_id not in resources[resource]:
        raise HTTPException(status_code=404, detail="Resource not found")

    item = resources[resource][resource_id]

    # Enforce ownership: only the owner (or a VIP user) may read the resource
    if item.get("owner_id") != current_user_id and current_user_id not in vip_users:
        raise HTTPException(status_code=403, detail="Access denied")

    return item


@app.post("/{resource}")
def create_resource(
    resource: str,
    data: dict,
    authorization: Optional[str] = Header(None),
):
    current_user_id = get_current_user(authorization)
    if resource not in resources:
        resources[resource] = {}
    next_id = len(resources[resource]) + 1
    # Record the owner so we can enforce access control later
    resources[resource][next_id] = {"id": next_id, "owner_id": current_user_id, **data}
    return resources[resource][next_id]
